                                    <div style={{ background: '#FFFFFF', borderRadius: '8px', padding: '10px', border: '1px solid #80CBC4' }}>
                                        <p style={{ fontSize: '13px', color: '#00695C', margin: 0 }}>⭐ <strong>Why important:</strong> They keep our community clean and healthy.</p>
                                    </div>
